     6	using Microsoft.EntityFrameworkCore;
     7	
     8	namespace InventoryFlow.Infrastructure.Transfers;
     9	
    10	/// <summary>Posts immutable warehouse transfers with a serializable, two-balance ledger update.</summary>
    11	public sealed class EfWarehouseTransferService(ApplicationDbContext dbContext) : IWarehouseTransferService
    12	{
    13	    public async Task<WarehouseTransfer?> RecordAsync(Guid workspaceId, Guid sourceWarehouseId, Guid destinationWarehouseId,
    14	        Guid productId, decimal quantity, string idempotencyKey, DateTimeOffset transferredAtUtc, CancellationToken cancellationToken)
    15	    {
    16	        quantity = InventoryMovement.ValidateQuantity(quantity);
    17	        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
    18	        if (sourceWarehouseId == destinationWarehouseId)
    19	            throw new DomainException("Source and destination warehouses must be different.");
    20	
    21	        var strategy = dbContext.Database.CreateExecutionStrategy();
    22	        return await strategy.ExecuteAsync(async () =>
    23	        {
    24	            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
    25	            var existing = await dbContext.WarehouseTransfers.SingleOrDefaultAsync(transfer => transfer.WorkspaceId == workspaceId &&
    26	                transfer.IdempotencyKey == idempotencyKey, cancellationToken);
    27	            if (existing is not null)
    28	            {
    29	                await transaction.CommitAsync(cancellationToken);
    30	                return existing;
    31	            }
    32	
    33	            var productExists = await dbContext.Products.AnyAsync(product => product.Id == productId &&
    34	                product.WorkspaceId == workspaceId && product.ArchivedAtUtc == null, cancellationToken);
    35	            var sourceExists = await dbContext.Warehouses.AnyAsync(warehouse => warehouse.Id == sourceWarehouseId &&
    36	                warehouse.WorkspaceId == workspaceId && warehouse.ArchivedAtUtc == null, cancellationToken);
    37	            var destinationExists = await dbContext.Warehouses.AnyAsync(warehouse => warehouse.Id == destinationWarehouseId &&
    38	                warehouse.WorkspaceId == workspaceId && warehouse.ArchivedAtUtc == null, cancellationToken);
    39	            if (!productExists || !sourceExists || !destinationExists)
    40	            {
    41	                await transaction.RollbackAsync(cancellationToken);
    42	                return null;
    43	            }
    44	
    45	            // Every transfer acquires both key/range locks in the same warehouse-ID order, including reverse transfers.
    46	            var firstWarehouseId = sourceWarehouseId.CompareTo(destinationWarehouseId) < 0 ? sourceWarehouseId : destinationWarehouseId;
    47	            var secondWarehouseId = firstWarehouseId == sourceWarehouseId ? destinationWarehouseId : sourceWarehouseId;
    48	            var firstBalance = await LockBalanceAsync(workspaceId, firstWarehouseId, productId, cancellationToken);
    49	            var secondBalance = await LockBalanceAsync(workspaceId, secondWarehouseId, productId, cancellationToken);
    50	
    51	            var sourceBalance = sourceWarehouseId == firstWarehouseId ? firstBalance : secondBalance;
    52	            var destinationBalance = destinationWarehouseId == firstWarehouseId ? firstBalance : secondBalance;
    53	            sourceBalance.Apply(-quantity);
    54	            destinationBalance.Apply(quantity);
    55	
    56	            var transferId = Guid.NewGuid();
    57	            var sourceMovement = new InventoryMovement(Guid.NewGuid(), workspaceId, sourceWarehouseId, productId,
    58	                InventoryMovementType.Issue, quantity, $"{transferId:N}:issue", sourceBalance.Quantity, transferredAtUtc);
    59	            var destinationMovement = new InventoryMovement(Guid.NewGuid(), workspaceId, destinationWarehouseId, productId,
    60	                InventoryMovementType.Receipt, quantity, $"{transferId:N}:receipt", destinationBalance.Quantity, transferredAtUtc);
    61	            var transfer = new WarehouseTransfer(transferId, workspaceId, sourceWarehouseId, destinationWarehouseId, productId,
    62	                quantity, idempotencyKey, sourceMovement.Id, destinationMovement.Id, transferredAtUtc);
    63	
    64	            dbContext.InventoryMovements.AddRange(sourceMovement, destinationMovement);
    65	            dbContext.WarehouseTransfers.Add(transfer);
    66	            await dbContext.SaveChangesAsync(cancellationToken);
    67	            await transaction.CommitAsync(cancellationToken);
    68	            return transfer;
    69	        });
    70	    }
    71	
    72	    public async Task<IReadOnlyList<WarehouseTransfer>> ListAsync(Guid workspaceId, CancellationToken cancellationToken) =>
    73	        await dbContext.WarehouseTransfers.AsNoTracking().Where(transfer => transfer.WorkspaceId == workspaceId)
    74	            .OrderByDescending(transfer => transfer.TransferredAtUtc).ThenByDescending(transfer => transfer.Id)
    75	            .ToListAsync(cancellationToken);
    76	
    77	    private async Task<InventoryBalance> LockBalanceAsync(Guid workspaceId, Guid warehouseId, Guid productId,
    78	        CancellationToken cancellationToken)
    79	    {
    80	        var balance = await dbContext.InventoryBalances.FromSqlInterpolated($"""
    81	            SELECT * FROM [InventoryBalances] WITH (UPDLOCK, HOLDLOCK)
    82	            WHERE [WorkspaceId] = {workspaceId} AND [WarehouseId] = {warehouseId} AND [ProductId] = {productId}
    83	            """).SingleOrDefaultAsync(cancellationToken);
    84	        if (balance is not null) return balance;
    85	
    86	        balance = new InventoryBalance(workspaceId, warehouseId, productId, 0m);
    87	        dbContext.InventoryBalances.Add(balance);
    88	        return balance;
    89	    }
    90	}

